INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('real-estate-moex-01172', 'real-estate', 'real-estate-moex-113-341b00dc', 'sub-real-estate-05', NULL, 'single_choice', '字為限，12分） 生活中也存在著我們以為是小事，但仔細思考，卻有其必須認真看待 的重要性。請從自己的生活經驗或見聞為例，以「生活中值得小題 大作的事」為題，撰文一篇。（38 分） 60210 臺灣知名劇團「屏風表演班」創辦人一生的傳奇，要從中華商場說起。 他的父親在西門町中華商場開了一間戲靴店，雖然日子過得勉強，但父親 教會他人生最重要的道理：無論賺錢與否，把一件事做好。對創辦人來說， 那件事非戲劇莫屬了。他大學第一次踏上舞臺就愛上戲劇，後因電視節目 「綜藝 100」成為家喻戶曉的喜劇演員，縱使在電視圈炙手可熱，但創辦 人始終不忘在舞臺上演出的滋味。', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:07+00:00", "source_pdf_sha1": "f508d75004ba", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "601", "s": "1501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文）", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 150, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01173', 'real-estate', 'real-estate-moex-113-341b00dc', 'sub-real-estate-05', NULL, 'single_choice', '年來，創辦人堅持「屏風表演班」演出的劇本一定要臺灣原創， 而非翻譯；他堅持，從頭栽培演員，學生演員也不例外；他堅持，收徒弟 就要從生活品格開始教起；他堅持，每一部戲都要讓每一位觀眾感動。作 為劇團的領航者，他的堅持讓屏風成為臺灣少數能「以戲養戲」的表演團 體，也讓屏風從觀眾席只有 100個座位的小劇場，走到世界舞臺。創辦人 從年輕到老，彷彿是為戲劇而活，他最為人知的一句座右銘是：「人，一 輩子能做好一件事，就功德圓滿了。」 現實中，「做好一件事」未必就能擁有令人稱羨的財富與地位，但想 達到「成功」的人生，都要有「做好一件事」的信念。不論過去與未來， 你都可以「做好一件事」，使自己更加完善。請以「做好一件事」為題作 文一篇，先根據上述分析「屏風表演班」創辦人「做好一件事」的意義， 再就個人生活經驗闡述「做好一件事」對人生的意義。（50 分）', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:07+00:00", "source_pdf_sha1": "f508d75004ba", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "601", "s": "1501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文）", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 27, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01174', 'real-estate', 'real-estate-moex-110-a7c7609b', 'sub-real-estate-04', NULL, 'essay', '甲與乙共有一筆土地，甲持分2/3，乙持分為1/3。乙分別於99年1月28
日、99 年 8 月 10 日、99 年 9 月 8 日設定最高限額抵押權與丙、丁、戊
等人。嗣後甲與乙於110年3月18日訴請法院分割，兩人並因此取得因
分割而形成單獨所有的土地，而上述三筆抵押權按應有部分比例移轉到
甲與乙之土地上。甲不服該抵押權移轉到自己分得單獨所有的土地上，遂
向法院起訴請求塗銷抵押權登記。請問甲之請求是否有理由？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:07+00:00", "source_pdf_sha1": "b35d5f9ece20", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法概要", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": "一", "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01175', 'real-estate', 'real-estate-moex-110-a7c7609b', 'sub-real-estate-04', NULL, 'essay', '甲為了避免債主追討以及法院強制執行拍賣其不動產，而與乙通謀虛偽
意思表示進行土地買賣。乙因此取得甲所有之 A地，並且完成移轉登記。
乙於 99 年 1 月 28 日死亡、其子女丙與丁於 99 年 2 月 2 日辦妥繼承登
記。請問丙丁何時取得 A 地所有權？又嗣後甲向丙與丁請求塗銷登
記，返還其所有之土地，請問甲之請求是否有理由？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:07+00:00", "source_pdf_sha1": "b35d5f9ece20", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法概要", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": "二", "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01176', 'real-estate', 'real-estate-moex-110-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲與乙訂立買賣契約，契約條款記載「…價金新臺幣陸拾捌萬元整（NT$860,000）。前揭捌拾陸萬 元價金應於訂約後10日內支付。」 若嗣後雙方就價金金額爭訟時，法院應如何決定價金？', '["應認為價金為最後書寫之文字：捌拾陸萬元", "應先探求當事人原意", "應認為價金為兩項金額之平均值：柒拾柒萬元", "如法院不能決定當事人原意，應以數字為準：NT$860,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:07+00:00", "source_pdf_sha1": "b35d5f9ece20", "answer_pdf_sha1": "b1fa2c55c282", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01177', 'real-estate', 'real-estate-moex-110-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '關於胎兒的敘述，下列何者正確？', '["人之權利能力，始於出生，終於死亡。胎兒無權利能力", "胎兒以將來非死產者為限，關於其個人利益之保護，視為既已出生", "胎兒為繼承人時，於胎兒出生前，他繼承人不得分割遺產", "胎兒為繼承人時，以其母為繼承人"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:07+00:00", "source_pdf_sha1": "b35d5f9ece20", "answer_pdf_sha1": "b1fa2c55c282", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01178', 'real-estate', 'real-estate-moex-110-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '關於失蹤人的敘述，下列何者正確？', '["失蹤人失蹤滿七年後，法院得因利害關係人或檢察官之聲請，為死亡之宣告", "失蹤人為八十歲以上者，得於失蹤滿五年後，為死亡之宣告", "失蹤人為遭遇特別災難者，得於特別災難終了滿三個月後，為死亡之宣告", "失蹤人失蹤後，未受死亡宣告前，其財產之管理，除其他法律另有規定者外，依破產法之規定"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:07+00:00", "source_pdf_sha1": "b35d5f9ece20", "answer_pdf_sha1": "b1fa2c55c282", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01179', 'real-estate', 'real-estate-moex-110-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '關於行為能力之敘述，下列何者錯誤？', '["受監護宣告之人之意思表示，無效，應由其法定代理人代為意思表示，並代受意思表示", "限制行為能力人未得法定代理人之允許，所為之單獨行為，無效", "未滿法定結婚年齡之男女，其結婚之法律效果並非無效，而是得撤銷", "為保障胎兒之行為能力，胎兒以將來非死產者為限，關於其個人利益之保護，視為既已出生"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:07+00:00", "source_pdf_sha1": "b35d5f9ece20", "answer_pdf_sha1": "b1fa2c55c282", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01180', 'real-estate', 'real-estate-moex-110-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '關於代理的敘述，下列何者正確？', '["代理權係以法律行為授與者，其授與應向代理人或向代理人對之為代理行為之第三人，以書面 授權方式代理為之", "代理人有數人者，其代理行為應單獨為之。但法律另有規定或本人另有意思表示者，不在此限", "由自己之行為表示以代理權授與他人，或知他人表示為其代理人而不為反對之表示者，對於第 三人應負授權人之責任。但第三人明知其無代理權或可得而知者，不在此限", "代理人於代理權限內，以本人名義所為之意思表示，直接對本人發生效力。而無代理權人以代 理人之名義所為之法律行為則為無效"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:07+00:00", "source_pdf_sha1": "b35d5f9ece20", "answer_pdf_sha1": "b1fa2c55c282", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01181', 'real-estate', 'real-estate-moex-110-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '下列何種法律行為屬法定書面要式行為？', '["動產所有權之拋棄", "子女之收養", "贈與契約", "演藝經紀契約"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:07+00:00", "source_pdf_sha1": "b35d5f9ece20", "answer_pdf_sha1": "b1fa2c55c282", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL)
